## 타입 호환성

TypeScript에서는 타입 이름이 달라도, 필요한 속성과 메서드를 가지고 있으면 같은 타입처럼 사용할 수 있다.

```typescript
interface Food {
  name: string;
  caloriePer100g: number;
  weightInGram: number;
}

function calcCalorie(food: Food) {
  return (food.caloriePer100g * food.weightInGram) / 100;
}

// 1. Food 타입과 정확히 일치
const apple: Food = {
  name: "사과",
  caloriePer100g: 52,
  weightInGram: 150,
};

calcCalorie(apple); // 가능

// 2. Food 타입과 전혀 다른 구조
interface Computer {
  brand: string;
  cpu: string;
  ramGB: number;
}

const myComputer: Computer = {
  brand: "LG",
  cpu: "Intel i7",
  ramGB: 16,
};

calcCalorie(myComputer); // 에러

// 3. Food와 일부 속성만 일치
interface Burger {
  name: string;
  caloriePer100g: number;
}

const burger: Burger = {
  name: "치즈버거",
  caloriePer100g: 295,
};

calcCalorie(burger); // 에러

// 4. Food라고 선언하지 않았지만 구조가 같음
const burgerWithWeight = {
  name: "치즈버거",
  caloriePer100g: 295,
  weightInGram: 220,
};

calcCalorie(burgerWithWeight); // 가능

// 5. Food보다 속성이 더 많음
const chickenBurger = {
  name: "치킨버거",
  caloriePer100g: 260,
  weightInGram: 240,
  protein: 28,
  price: 6500,
};

calcCalorie(chickenBurger); // 가능
```

